steps.script:
() => {
  const needles=['ml-hero__btn','Cormorant','20px 52px'];
  const scripts=[...document.querySelectorAll('script:not([src])')];
  let inlineHit=null;
  for(const s of scripts){ const t=s.textContent||''; const k=needles.find(n=>t.indexOf(n)>=0); if(k){ inlineHit={key:k, len:t.length, around:t.slice(Math.max(0,t.indexOf(k)-200), t.indexOf(k)+400)}; break; } }
  return {
    inlineHit,
    scriptSrcs: [...document.scripts].map(s=>s.src).filter(u=>u && u.indexOf('meandlia.com')>=0).map(u=>u.split('?')[0])
  };
}
